const safeErr = (e) => {
  if (e == null) return 'unknown error';
  if (typeof e === 'string') return e;
  if (e.message || e.description) return String(e.message || e.description);
  try { return JSON.stringify(e).slice(0, 120); } catch { return 'unknown error'; }
};

// Check every active VPN server: Marzban panel if configured, else stats agent.
// Code sandbox has no fetch: use require('http'/'https') (NODE_FUNCTION_ALLOW_BUILTIN).
const http = require('http');
const https = require('https');

function request(method, url, { headers = {}, body = null, timeout = 8000 } = {}) {
  return new Promise((resolve, reject) => {
    const m = url.match(/^(https?):\/\/([^\/:]+)(?::(\d+))?(\/.*)?$/);
    if (!m) return reject(new Error('bad url: ' + url));
    const lib = m[1] === 'https' ? https : http;
    const req = lib.request({
      method, hostname: m[2], port: m[3] ? Number(m[3]) : (m[1] === 'https' ? 443 : 80),
      path: m[4] || '/', headers, timeout,
    }, (res) => {
      let data = '';
      res.on('data', (c) => data += c);
      res.on('end', () => resolve({ status: res.statusCode, body: data }));
    });
    req.on('timeout', () => { req.destroy(new Error('timeout after ' + timeout + 'ms')); });
    req.on('error', reject);
    if (body) req.write(body);
    req.end();
  });
}

const resp = $('Fetch VPN Servers').first().json;
const list = Array.isArray(resp.body) ? resp.body : null;

if (!list) {
  return [{ json: { servers: [], fetchError: safeErr(resp.error || 'vpn_servers fetch returned no array') } }];
}

const fmtBytes = (b) => {
  if (!b) return '0 B';
  const u = ['B', 'KB', 'MB', 'GB', 'TB'];
  const i = Math.min(u.length - 1, Math.floor(Math.log(Math.abs(b)) / Math.log(1024)));
  return (b / Math.pow(1024, i)).toFixed(1) + ' ' + u[i];
};

const out = [];
for (const srv of list) {
  const base = { name: srv.name, country: srv.country_code, city: srv.city, ip: srv.ip_address };
  try {
    if (srv.marzban_api_url) {
      const h = { 'Content-Type': 'application/x-www-form-urlencoded' };
      if (srv.marzban_api_key) h['X-Marzban-Key'] = srv.marzban_api_key;
      const tr = await request('POST', srv.marzban_api_url + '/admin/token', {
        headers: h,
        body: 'username=' + encodeURIComponent(srv.marzban_admin_user || '') +
              '&password=' + encodeURIComponent(srv.marzban_admin_pass || ''),
      });
      if (tr.status < 200 || tr.status >= 300) { out.push({ ...base, kind: 'marzban', ok: false, detail: 'auth HTTP ' + tr.status }); continue; }
      const token = JSON.parse(tr.body).access_token;
      const sh = { Authorization: 'Bearer ' + token };
      if (srv.marzban_api_key) sh['X-Marzban-Key'] = srv.marzban_api_key;
      const sr = await request('GET', srv.marzban_api_url + '/system', { headers: sh });
      if (sr.status < 200 || sr.status >= 300) { out.push({ ...base, kind: 'marzban', ok: false, detail: 'system HTTP ' + sr.status }); continue; }
      const sys = JSON.parse(sr.body);
      const memPct = sys.mem_total ? Math.round(100 * sys.mem_used / sys.mem_total) : null;
      out.push({ ...base, kind: 'marzban', ok: true,
        detail: (sys.total_user || 0) + ' users, ' + (sys.users_active || 0) + ' active, ↓' +
                fmtBytes(sys.incoming_bandwidth) + ' ↑' + fmtBytes(sys.outgoing_bandwidth) +
                (memPct === null ? '' : ', mem ' + memPct + '%') });
    } else if (srv.stats_agent_url) {
      const ar = await request('GET', srv.stats_agent_url, {
        headers: { Authorization: 'Bearer ' + (srv.stats_agent_token || '') },
      });
      if (ar.status < 200 || ar.status >= 300) { out.push({ ...base, kind: 'agent', ok: false, detail: 'agent HTTP ' + ar.status }); continue; }
      const st = JSON.parse(ar.body);
      const conns = (st.xray && st.xray.connections && st.xray.connections.total) || 0;
      const xrayUp = !!(st.xray && st.xray.active);
      out.push({ ...base, kind: 'agent', ok: xrayUp,
        detail: (xrayUp ? '' : 'XRAY DOWN, ') + conns + ' conns, load ' +
                (st.cpu ? st.cpu.load1 : '?') + ', mem ' + (st.mem ? st.mem.used_pct : '?') + '%' });
    } else {
      out.push({ ...base, kind: 'none', ok: false, detail: 'no monitoring endpoint configured' });
    }
  } catch (e) {
    out.push({ ...base, kind: srv.marzban_api_url ? 'marzban' : 'agent', ok: false, detail: safeErr(e).slice(0, 80) });
  }
}
return [{ json: { servers: out, fetchError: null } }];

const safeErr = (e) => {
  if (e == null) return 'unknown error';
  if (typeof e === 'string') return e;
  if (e.message || e.description) return String(e.message || e.description);
  try { return JSON.stringify(e).slice(0, 120); } catch { return 'unknown error'; }
};

// Build the Telegram message. Same data feeds daily summary and alerts.
const esc = (s) => String(s ?? '').replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;');

function get(name) { try { return $(name).first().json; } catch { return null; } }
function isHttpOk(d) { if (!d || d.error) return false; return d.statusCode >= 200 && d.statusCode < 400; }
function errDetail(d) {
  if (!d) return 'no data';
  if (d.error) return safeErr(d.error).slice(0, 80);
  return 'HTTP ' + d.statusCode;
}

const flagMap = { PL: '\u{1F1F5}\u{1F1F1}', SE: '\u{1F1F8}\u{1F1EA}', US: '\u{1F1FA}\u{1F1F8}',
  HK: '\u{1F1ED}\u{1F1F0}', CA: '\u{1F1E8}\u{1F1E6}', DE: '\u{1F1E9}\u{1F1EA}', IL: '\u{1F1EE}\u{1F1F1}',
  RU: '\u{1F1F7}\u{1F1FA}', NL: '\u{1F1F3}\u{1F1F1}', GB: '\u{1F1EC}\u{1F1E7}', SG: '\u{1F1F8}\u{1F1EC}' };

const website = get('Check Website');
const blogApi = get('Check Blog API');
const n8nNode = get('Check n8n');
const simnetiq = get('Check Simnetiq');
const serverData = get('Check VPN Servers') || {};
const servers = serverData.servers || [];
const fetchError = serverData.fetchError || null;

const coldRaw = get('Check Cold Outreach');
const cold = (coldRaw && coldRaw.body) ? coldRaw.body : (coldRaw || {});
const hasCold = cold && typeof cold === 'object' && typeof cold.total_prospects !== 'undefined';

const icon = (ok) => ok ? '✅' : '❌';

const services = [
  { name: 'Website', ok: isHttpOk(website), data: website },
  { name: 'Blog API', ok: isHttpOk(blogApi), data: blogApi },
  { name: 'n8n', ok: isHttpOk(n8nNode), data: n8nNode },
  { name: 'Simnetiq', ok: isHttpOk(simnetiq), data: simnetiq },
];

const hasFailures = services.some(s => !s.ok) || servers.some(s => !s.ok) || !!fetchError;

// Schedule fires at Berlin-local hours (container TZ Europe/Berlin); 9 = daily summary.
let hour;
try { hour = $now.hour; } catch { hour = new Date().getHours(); }
const isDailySummary = hour === 9;

// Alert dedupe: re-alert only when the failure set changes or 12h passed.
const sd = $getWorkflowStaticData('global');
const failing = [
  ...services.filter(s => !s.ok).map(s => s.name),
  ...servers.filter(s => !s.ok).map(s => s.name),
  ...(fetchError ? ['vpn_servers fetch'] : []),
].sort();
const fp = failing.join('|');
const lastFp = sd.lastAlertFingerprint || '';
const lastAt = sd.lastAlertAt || 0;
const nowMs = Date.now();

let shouldSend = false;
let header = '';
if (isDailySummary) {
  shouldSend = true;
  header = '\u{1F4CA} <b>Daily Doppler Status</b>';
} else if (fp && (fp !== lastFp || nowMs - lastAt > 12 * 3600 * 1000)) {
  shouldSend = true;
  header = '\u{1F534} <b>ALERT: Service Issue</b>';
} else if (!fp && lastFp) {
  shouldSend = true;
  header = '✅ <b>Recovered — all services OK</b>';
}
if (shouldSend) { sd.lastAlertFingerprint = fp; sd.lastAlertAt = fp ? nowMs : 0; }

const ts = new Date().toISOString().replace('T', ' ').slice(0, 16) + ' UTC';
const lines = [];
if (shouldSend) {
  lines.push(header);
  lines.push('');
  lines.push('<b>Services</b>');
  for (const s of services) {
    let detail = s.ok ? 'OK' : errDetail(s.data);
    if (s.name === 'Blog API' && s.ok && s.data.body && s.data.body.stats) {
      detail = s.data.body.stats.total_posts + ' posts, ' + s.data.body.stats.total_translations + ' translations';
    }
    lines.push(icon(s.ok) + ' <b>' + s.name + ':</b> ' + esc(detail));
  }
  lines.push('');
  lines.push('<b>VPN Servers (' + servers.length + ')</b>');
  if (fetchError) lines.push('❌ <b>server list:</b> ' + esc(fetchError));
  for (const srv of servers) {
    const flag = flagMap[srv.country] || '\u{1F310}';
    lines.push(icon(srv.ok) + ' ' + flag + ' <b>' + esc(srv.name) + (srv.city ? ' (' + esc(srv.city) + ')' : '') + ':</b> ' + esc(srv.detail || ''));
  }
  if (isDailySummary && hasCold) {
    lines.push('');
    lines.push('<b>Cold Outreach (last 24h)</b>');
    lines.push('✉️ Sent: <b>' + (cold.sent_total_24h || 0) + '</b>  (S1: ' + (cold.sent_step1_24h || 0) + ' · S2: ' + (cold.sent_step2_24h || 0) + ' · S3: ' + (cold.sent_step3_24h || 0) + ')');
    lines.push('↩️ Replies: <b>' + (cold.replies_24h || 0) + '</b>  ·  ❌ Opt-outs: <b>' + (cold.opt_outs_24h || 0) + '</b>');
    lines.push('⏳ In queue: <b>' + (cold.in_queue || 0) + '</b>  (due now: ' + (cold.queued_due_now || 0) + ')');
    lines.push('\u{1F4C8} Lifetime: ' + (cold.total_prospects || 0) + ' prospects · ' + (cold.total_replied || 0) + ' replies · ' + (cold.total_opted_out || 0) + ' opt-outs');
  }
  lines.push('');
  lines.push('<i>' + ts + '</i>');
}
return [{ json: { shouldSend, message: lines.join('\n'), isDailySummary, hasFailures } }];
